const item = $input.first()?.json || {};
const webhookBody = $('Webhook').first()?.json?.body || {};
const message = String(webhookBody.message ?? item.message ?? '').trim();
const session_id = String(webhookBody.session_id ?? webhookBody.sessionId ?? item.session_id ?? `web-${Date.now()}`);
const raw = String(item.output ?? item.text ?? '').trim();

function fallbackClassify(msg) {
  const m = String(msg || '').toLowerCase();
  if (!m || m.length <= 2 || /^(hi|hello|hey|xin chào|chào|alo|g|gu)$/i.test(m)) {
    return { intent: 'general', product: 'Xin chào! Tôi có thể hỗ trợ kiểm tra đơn hàng, gợi ý sản phẩm, thanh toán hoặc tạo ticket hỗ trợ cho bạn.' };
  }
  if (/(recommend|suggest|gợi ý|đề xuất|sản phẩm|product|toys|toy|đồ chơi|category|danh mục|mua gì)/i.test(m)) {
    const product = /toys|toy|đồ chơi/i.test(m) ? 'toys' : (/health|beauty|làm đẹp/i.test(m) ? 'health_beauty' : (/sport|thể thao/i.test(m) ? 'sports_leisure' : ''));
    return { intent: 'product_recommendation', product };
  }
  if (/(order|đơn hàng|shipping|delivery|giao hàng|vận chuyển|track|theo dõi|payment|thanh toán|refund|hoàn tiền)/i.test(m)) {
    return { intent: 'order_status', product: '' };
  }
  if (/(ticket|support|hỗ trợ|khiếu nại|complaint|lỗi|broken|hỏng|đổi trả|return|bảo hành)/i.test(m)) {
    return { intent: 'support_ticket', product: '' };
  }
  return { intent: 'general', product: 'Mình đã nhận được tin nhắn của bạn. Bạn muốn kiểm tra đơn hàng, gợi ý sản phẩm hay tạo ticket hỗ trợ?' };
}

let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch (e) {
  parsed = fallbackClassify(message);
}

const valid = ['order_status', 'support_ticket', 'product_recommendation', 'general'];
if (!parsed || !valid.includes(parsed.intent)) parsed = fallbackClassify(message);
if (!parsed.product) parsed.product = fallbackClassify(message).product || '';

return [{
  json: {
    ...item,
    body: webhookBody,
    message,
    session_id,
    category: {
      intent: parsed.intent,
      product: String(parsed.product || '')
    }
  }
}];

const now = new Date();
const dateStr = now.toISOString().slice(0,10).replace(/-/g, '');
const random = Math.floor(1000 + Math.random() * 9000);
return `TKT-${dateStr}-${random}`;

function htmlDecode(text) {
  return String(text || '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ');
}
function stripHtml(text) {
  return String(text || '').replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n').replace(/<[^>]*>/g, '');
}
function cleanText(value) {
  let text = htmlDecode(stripHtml(value));
  text = text
    .replace(/```[\s\S]*?```/g, '')
    .replace(/\*\*/g, '')
    .replace(/__/g, '')
    .replace(/#{1,6}\s?/g, '')
    .replace(/^\s*[\-*+]\s+/gm, '- ')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  if (!text) {
    text = 'Xin lỗi, hệ thống chưa tạo được phản hồi đầy đủ. Bạn vui lòng thử lại hoặc cung cấp thêm thông tin.';
  }
  return text;
}
function escapeHtml(text) {
  return String(text || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;')
    .replace(/\n/g, '<br>');
}
function extract(regex, text) {
  const m = String(text || '').match(regex);
  return m ? m[0] : '';
}

const webhook = $('Webhook').first()?.json || {};
const body = webhook.body || {};
const userMessage = String(body.message || $json.message || '').trim();
const rawResponse = $json.response || $json.output || $json.category?.product || '';
const response = cleanText(rawResponse);
const intent = $json.intent || $json.category?.intent || 'order_status';
const combined = `${userMessage}\n${response}`;

const orderId = body.order_id || extract(/ORD-[A-Z0-9-]+|[0-9A-Za-z]{12,}/i, combined);
const ticketId = body.ticket_id || extract(/TKT-[0-9A-Z-]+/i, combined);
const productId = body.product_id || extract(/DEMO-[A-Z0-9-]+|HB-[A-Z0-9-]+|TOY-[A-Z0-9-]+|COMP-[A-Z0-9-]+|SPORT-[A-Z0-9-]+/i, combined);
const email = body.email || body.user_email || extract(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i, combined);
const category = $json.category?.product || body.product_category_name || '';

return [{
  json: {
    ...$json,
    response,
    response_html: escapeHtml(response),
    intent,
    log_session_id: String(body.session_id || body.sessionId || $json.session_id || 'default-session'),
    log_user_email: String(email || ''),
    log_user_message: userMessage,
    log_bot_response: response,
    log_product_category_name: String(category || ''),
    log_product_id: String(productId || ''),
    log_order_id: String(orderId || ''),
    log_ticket_id: String(ticketId || ''),
    log_channel: String(body.channel || 'web_chat'),
    log_status: 'success',
    log_metadata: {
      source: 'n8n_ecommerce_customer_support',
      branch: 'Order',
      webhook_url: webhook.webhookUrl || '',
      execution_mode: webhook.executionMode || '',
      user_agent: webhook.headers?.['user-agent'] || '',
      origin: webhook.headers?.origin || '',
      cleaned_html: true,
      has_response_html: true
    }
  }
}];

